package com.capacitorcommunity.videorecorder;

import android.Manifest;
import android.graphics.Color;
import android.hardware.Camera;
import android.media.MediaRecorder;
import android.net.Uri;
import android.util.DisplayMetrics;
import android.view.SurfaceHolder;
import android.view.SurfaceView;
import android.view.ViewGroup;
import android.view.ViewParent;
import android.widget.FrameLayout;

import com.getcapacitor.FileUtils;
import com.getcapacitor.JSObject;
import com.getcapacitor.PermissionState;
import com.getcapacitor.annotation.CapacitorPlugin;
import com.getcapacitor.annotation.Permission;

import com.getcapacitor.Plugin;
import com.getcapacitor.PluginCall;
import com.getcapacitor.PluginMethod;

import androidx.coordinatorlayout.widget.CoordinatorLayout;

import java.io.File;
import java.io.IOException;

@CapacitorPlugin(
        name = "VideoRecorder",
        permissions = {
            @Permission(alias = "camera", strings = { Manifest.permission.CAMERA }),
            @Permission(alias = "audio", strings = { Manifest.permission.RECORD_AUDIO })
        }
)
public class VideoRecorderPlugin extends Plugin implements SurfaceHolder.Callback {
    private Camera camera;
    private SurfaceView mPreview;
    private MediaRecorder mediaRecorder;
    private boolean isRecording = false;
    private File mOutputFile;

    @Override
    public void load() {
        super.load();
        android.util.Log.d("VideoRecorder", "v11.0 - MediaRecorder Architecture");
    }

    @PluginMethod()
    public void initialize(final PluginCall call) {
        if (getPermissionState("camera") != PermissionState.GRANTED || 
            getPermissionState("audio") != PermissionState.GRANTED) {
            requestPermissions(call);
            return;
        }

        getActivity().runOnUiThread(() -> {
            try {
                if (mPreview != null) {
                    ((ViewGroup) bridge.getWebView().getParent()).removeView(mPreview);
                }

                DisplayMetrics metrics = new DisplayMetrics();
                getActivity().getWindowManager().getDefaultDisplay().getMetrics(metrics);
                int screenWidth = metrics.widthPixels;
                int screenHeight = metrics.heightPixels;

                mPreview = new SurfaceView(getContext());
                CoordinatorLayout.LayoutParams camParams = new CoordinatorLayout.LayoutParams(screenWidth, screenHeight / 2);
                camParams.topMargin = 0;
                mPreview.setLayoutParams(camParams);
                
                mPreview.getHolder().addCallback(this);
                ((ViewGroup) bridge.getWebView().getParent()).addView(mPreview, 0, camParams);

                CoordinatorLayout.LayoutParams webParams = new CoordinatorLayout.LayoutParams(screenWidth, screenHeight / 2);
                webParams.topMargin = screenHeight / 2;
                bridge.getWebView().setLayoutParams(webParams);
                
                bridge.getWebView().setElevation(10);
                mPreview.setElevation(5);

                call.resolve();
            } catch (Exception e) {
                call.reject("Init failed: " + e.getMessage());
            }
        });
    }

    @PluginMethod()
    public void start(PluginCall call) {
        startRecording(call);
    }

    @PluginMethod()
    public void startRecording(final PluginCall call) {
        getActivity().runOnUiThread(new Runnable() {
            @Override
            public void run() {
                if (isRecording) {
                    call.reject("Camera is already recording.");
                    return;
                }

                try {
                    // CRITICAL: Unlock camera for video use
                    if (camera != null) {
                        camera.unlock();
                    } else {
                        call.reject("Camera hardware not available.");
                        return;
                    }

                    mediaRecorder = new MediaRecorder();
                    mediaRecorder.setCamera(camera);
                    
                    // Audio/Video Sources configuration
                    mediaRecorder.setAudioSource(MediaRecorder.AudioSource.CAMCORDER);
                    mediaRecorder.setVideoSource(MediaRecorder.VideoSource.CAMERA);
                    
                    // Set output format and profile
                    mediaRecorder.setOutputFormat(MediaRecorder.OutputFormat.MPEG_4);
                    mediaRecorder.setVideoEncoder(MediaRecorder.VideoEncoder.H264);
                    mediaRecorder.setAudioEncoder(MediaRecorder.AudioEncoder.AAC);
                    
                    // Specify a valid temporary file path
                    String rawPath = getActivity().getCacheDir().getAbsolutePath() + "/claim_video.mp4";
                    mediaRecorder.setOutputFile(rawPath);
                    mOutputFile = new File(rawPath);

                    // Set preview display
                    mediaRecorder.setPreviewDisplay(mPreview.getHolder().getSurface());

                    // CRITICAL: Must prepare BEFORE starting
                    mediaRecorder.prepare();
                    mediaRecorder.start();
                    
                    isRecording = true;
                    
                    JSObject ret = new JSObject();
                    ret.put("status", "started");
                    call.resolve(ret);

                } catch (Exception e) {
                    isRecording = false;
                    if (mediaRecorder != null) {
                        mediaRecorder.reset();
                        mediaRecorder.release();
                        mediaRecorder = null;
                    }
                    if (camera != null) {
                        camera.lock();
                    }
                    call.reject("CRITICAL START FAILURE: " + e.getMessage());
                }
            }
        });
    }

    @PluginMethod()
    public void stop(PluginCall call) {
        stopRecording(call);
    }

    @PluginMethod()
    public void stopRecording(final PluginCall call) {
        getActivity().runOnUiThread(new Runnable() {
            @Override
            public void run() {
                // If the flag is false, we know native side never actually started successfully
                if (!isRecording || mediaRecorder == null) {
                    call.reject("Cannot stop recording. Hardware was never successfully started.");
                    return;
                }

                try {
                    mediaRecorder.stop();
                    mediaRecorder.reset();
                    mediaRecorder.release();
                    mediaRecorder = null;
                    
                    if (camera != null) {
                        camera.lock(); // Re-lock camera for preview
                    }
                    
                    isRecording = false;
                    
                    // Return the local file path so frontend can upload to Firebase Storage
                    String rawPath = getActivity().getCacheDir().getAbsolutePath() + "/claim_video.mp4";
                    JSObject ret = new JSObject();
                    ret.put("videoUrl", FileUtils.getPortablePath(getContext(), bridge.getLocalUrl(), Uri.fromFile(mOutputFile)));
                    call.resolve(ret);

                } catch (RuntimeException stopException) {
                    // This catches the exact "Failed to stop" native crash gracefully
                    isRecording = false;
                    if (mediaRecorder != null) {
                        mediaRecorder.reset();
                        mediaRecorder.release();
                        mediaRecorder = null;
                    }
                    if (camera != null) {
                        camera.lock();
                    }
                    call.reject("MediaRecorder stop failed. This happens if stop() is called immediately after start() or if no video frames were received: " + stopException.getMessage());
                }
            }
        });
    }

    @Override
    public void surfaceCreated(SurfaceHolder holder) {
        try {
            camera = Camera.open(0); // FORCE REAR
            camera.setPreviewDisplay(holder);
            camera.setDisplayOrientation(90);
            camera.startPreview();
        } catch (Exception e) {
            android.util.Log.e("VideoRecorder", "Camera open failed: " + e.getMessage());
        }
    }

    @Override public void surfaceChanged(SurfaceHolder holder, int format, int w, int h) {}
    @Override public void surfaceDestroyed(SurfaceHolder holder) {
        if (camera != null) {
            camera.stopPreview();
            camera.release();
            camera = null;
        }
    }
}
